// api/create-checkout-session.js
// Creates a Stripe Hosted Checkout session from a cart of { handle, size, quantity }.
// The server is the source of truth for price — it looks up the Stripe Price ID
// for each product handle in data/stripe-products.json (generated by scripts/stripe-sync.js).

import Stripe from 'stripe';
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const MAPPING_PATH = path.resolve(__dirname, '..', 'data', 'stripe-products.json');

let productMap = null;
function loadProductMap() {
  if (productMap) return productMap;
  const raw = fs.readFileSync(MAPPING_PATH, 'utf8');
  productMap = JSON.parse(raw);
  return productMap;
}

export default async function handler(req, res) {
  res.setHeader('Access-Control-Allow-Origin', 'https://protonlab.cc');
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') {
    return res.status(200).end();
  }

  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { items, customerEmail, customerName } = req.body;

  // items = [{ handle: 'ss-race-jersey', size: 'M', quantity: 1, image?: '...' }]

  if (!Array.isArray(items) || items.length === 0) {
    return res.status(400).json({ error: 'No items provided' });
  }

  let map;
  try {
    map = loadProductMap();
  } catch (err) {
    console.error('Failed to load product mapping:', err);
    return res.status(500).json({ error: 'Product catalog unavailable' });
  }

  const resolved = [];
  for (const item of items) {
    if (!item || typeof item.handle !== 'string' || typeof item.size !== 'string') {
      return res.status(400).json({ error: 'Invalid cart item' });
    }
    const entry = map[item.handle];
    if (!entry || !entry.priceId) {
      return res.status(400).json({ error: `Unknown product: ${item.handle}` });
    }
    const quantity = Number.isFinite(item.quantity) && item.quantity > 0 ? Math.floor(item.quantity) : 1;
    resolved.push({
      handle: item.handle,
      size: item.size,
      quantity,
      priceId: entry.priceId,
      name: entry.name,
      image: typeof item.image === 'string' ? item.image : undefined,
    });
  }

  try {
    const session = await stripe.checkout.sessions.create({
      payment_method_types: ['card'],
      mode: 'payment',

      customer_email: customerEmail || undefined,

      line_items: resolved.map((item) => ({
        price: item.priceId,
        quantity: item.quantity,
      })),

      // Stripe Checkout doesn't allow per-line-item descriptions when using a
      // Price ID, so surface size info via custom_text so the customer sees it
      // on the hosted page. Fulfillment still uses metadata.items (authoritative).
      custom_text: {
        submit: {
          message: 'Sizes: ' + resolved.map(i => `${i.name} — ${i.size}`).join(', '),
        },
      },

      payment_intent_data: {
        metadata: {
          name: customerName || '',
          email: customerEmail || '',
          product: resolved.map(i => i.name).join(', '),
          items: JSON.stringify(
            resolved.map(i => ({ handle: i.handle, size: i.size, qty: i.quantity }))
          ),
        },
      },

      success_url: `${process.env.SITE_URL}/success?session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${process.env.SITE_URL}/cancel`,
    });

    res.status(200).json({ url: session.url });
  } catch (err) {
    console.error('Stripe session creation error:', err);
    res.status(500).json({ error: 'Failed to create checkout session' });
  }
}
